import React from "react";
import KitsContainer from "../../helpers/FormContainer";
import type { ITreeSelect } from "@lmb-it/kitsconcerto-types";
import { TreeSelect } from "@lmb-it/kitsconcertomobile";
import { ClHelper } from "../../helpers/Functions";
import { useTreeBuild } from "../hooks/useTreeBuild";
import { useComponentDefaults, useResolvedStyle } from "@lmb-it/kitsconcerto/hooks";

const KitsTreeSelect = <T = any,>({ ref, ...rawProps }: ITreeSelect) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('TreeSelect', rawProps, 'Select');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        id,
        placeholder,
        required,
        disabled,
        helperText,
        attached,
        isFloatedLabel,
        inputSize,
        valueMode,
        isMultiple,
        localProps,
        withFilter,
        filterBy,
        hideError,
        onlyParentsWithChildren,
        resetFilterOnHide,
        scrollHeight,
        emptyMessage,
        showClear,
    } = props;

    const { nodes, value, handleChange } = useTreeBuild<T>({
        isStructured: props.isStructured,
        ref,
    });



    const Element = (
        <TreeSelect
            value={value}
            filter={withFilter}
            filterBy={filterBy}
            options={nodes}
            display={isMultiple ? valueMode : "comma"}
            onChange={handleChange}
            selectionMode={isMultiple ? 'checkbox' : 'single'}
            placeholder={placeholder}
            disabled={disabled}
            invalid={invalid}
            showClear={showClear ?? !required}
            isModal={false}
            onlyParentsWithChildren={onlyParentsWithChildren}
            resetFilterOnHide={resetFilterOnHide}
            scrollHeight={scrollHeight}
            emptyMessage={emptyMessage}
            style={resolvedRootStyle && Object.keys(resolvedRootStyle).length ? resolvedRootStyle : (Object.keys(resolvedThemeStyle).length ? resolvedThemeStyle : undefined)}
            {...localProps}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsTreeSelect;
